// src/components/panels/AIChatPanel.jsx
import React, { useState, useRef, useEffect } from 'react';
import { PanelBase } from '../index';
import { aiAPI } from '../../services/api';
import useStore from '../../store/useStore';

const QUICK = [
  'Ada kemacetan di Palembang sekarang?',
  'SPBU terdekat dari lokasi saya',
  'Kondisi cuaca Palembang hari ini',
  'Rute tercepat ke Jembatan Ampera',
  'Tips berkendara saat hujan',
  'Area mana yang paling ramai permintaan driver?',
];

export default function AIChatPanel({ isOpen, onClose, userLocation, weather, route, destination }) {
  const { aiMessages, addAIMessage, user } = useStore();
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [aiContext, setAiContext] = useState({});
  const scrollRef = useRef(null);

  // Greeting saat pertama dibuka
  useEffect(() => {
    if (aiMessages.length === 0) {
      const h = new Date().getHours();
      const gr = h < 12 ? 'Selamat pagi' : h < 17 ? 'Selamat siang' : 'Selamat sore';
      addAIMessage({
        role: 'assistant',
        content: `${gr}! Saya RouteAI, asisten navigasi cerdas Anda.\n\nSaya dapat membantu:\n• Info kemacetan & rute alternatif\n• Kondisi cuaca & peringatan banjir\n• Rekomendasi area untuk driver\n• SPBU, rumah sakit, & tempat lainnya\n• Tips berkendara aman\n\nKetik pertanyaan Anda!`,
        ts: new Date()
      });
    }
  }, []);

  // Update context setiap 30 detik
  useEffect(() => {
    if (!isOpen) return;
    const updateContext = () => {
      if (userLocation && weather) {
        setAiContext({
          city: 'Palembang',
          weather: weather.temperature ? `${weather.temperature}°C, ${weather.description}` : 'Berawan 31°C',
          userLocation: `${userLocation.lat.toFixed(4)}, ${userLocation.lng.toFixed(4)}`,
          activeRoute: destination ? { from: 'Lokasi Anda', to: destination.name, distance: route?.distanceKm || '?' } : null,
          vehicle: user?.preferences?.vehicle || 'Mobil'
        });
      }
    };
    updateContext();
    const interval = setInterval(updateContext, 30000);
    return () => clearInterval(interval);
  }, [isOpen, userLocation, weather, destination, route, user]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [aiMessages, loading]);

  const send = async (text) => {
    const msg = (text || input).trim();
    if (!msg || loading) return;
    setInput('');
    addAIMessage({ role: 'user', content: msg, ts: new Date() });
    setLoading(true);
    try {
      const history = aiMessages.slice(-8).map(m => ({ role: m.role, content: m.content }));
      const res = await aiAPI.chat(msg, history, aiContext);
      addAIMessage({ role: 'assistant', content: res.data.data.reply, ts: new Date() });
    } catch (err) {
      addAIMessage({ role: 'assistant', content: 'Maaf, layanan AI sedang tidak tersedia. Coba lagi nanti.', ts: new Date() });
    }
    setLoading(false);
  };

  return (
    <PanelBase isOpen={isOpen} onClose={onClose} title="" maxHeight="86%"
      headerRight={
        <div style={{ display: 'flex', alignItems: 'center', gap: 9 }}>
          <div style={{ width: 30, height: 30, borderRadius: 8, background: '#6B5CE7', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2" strokeLinecap="round"><path d="M12 2a2 2 0 012 2c0 .74-.4 1.39-1 1.73V7h1a7 7 0 017 7h1a1 1 0 011 1v3a1 1 0 01-1 1h-1v1a2 2 0 01-2 2H5a2 2 0 01-2-2v-1H2a1 1 0 01-1-1v-3a1 1 0 011-1h1a7 7 0 017-7h1V5.73A2 2 0 0110 4a2 2 0 012-2z"/></svg>
          </div>
          <div>
            <div style={{ fontSize: 14, fontWeight: 600 }}>RouteAI Assistant</div>
            <div style={{ fontSize: 10, color: '#1FAD8E' }}>Online — Claude AI</div>
          </div>
        </div>
      }
    >
      {/* Quick prompts */}
      <div style={{ display: 'flex', gap: 7, overflowX: 'auto', paddingBottom: 10, scrollbarWidth: 'none', marginBottom: 4 }}>
        {QUICK.map((q, i) => (
          <button key={i} onClick={() => send(q)}
            style={{ whiteSpace: 'nowrap', padding: '6px 12px', background: '#21262D', borderRadius: 14, fontSize: 12, border: '0.5px solid rgba(255,255,255,0.08)', color: '#F0F6FC', cursor: 'pointer', flexShrink: 0 }}>
            {q.length > 30 ? q.slice(0, 28) + '...' : q}
          </button>
        ))}
      </div>

      {/* Messages */}
      <div ref={scrollRef} style={{ display: 'flex', flexDirection: 'column', gap: 9, minHeight: 200, maxHeight: 340, overflowY: 'auto', marginBottom: 12 }}>
        {aiMessages.map((m, i) => (
          <div key={i} style={{ maxWidth: '84%', padding: '9px 13px', borderRadius: 15, fontSize: 13, lineHeight: 1.55, alignSelf: m.role === 'user' ? 'flex-end' : 'flex-start', background: m.role === 'user' ? '#6B5CE7' : '#21262D', color: '#F0F6FC', borderBottomRightRadius: m.role === 'user' ? 3 : 15, borderBottomLeftRadius: m.role === 'user' ? 15 : 3, whiteSpace: 'pre-line' }}>
            {m.role === 'assistant' && <div style={{ fontSize: 10, fontWeight: 600, color: '#7B6FFF', marginBottom: 5 }}>RouteAI</div>}
            {m.content}
          </div>
        ))}
        {loading && (
          <div style={{ alignSelf: 'flex-start', background: '#21262D', padding: '9px 13px', borderRadius: 15, borderBottomLeftRadius: 3 }}>
            <div style={{ fontSize: 10, fontWeight: 600, color: '#7B6FFF', marginBottom: 5 }}>RouteAI</div>
            <div className="loading-dots"><div className="loading-dot"/><div className="loading-dot"/><div className="loading-dot"/></div>
          </div>
        )}
      </div>

      {/* Input */}
      <div style={{ display: 'flex', gap: 8, borderTop: '0.5px solid rgba(255,255,255,0.07)', paddingTop: 12 }}>
        <input
          style={{ flex: 1, padding: '9px 12px', fontSize: 13 }}
          placeholder="Tanya RouteAI..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && send()}
        />
        <button onClick={() => send()}
          style={{ width: 40, height: 40, borderRadius: 11, background: '#6B5CE7', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="#fff"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>
        </button>
      </div>
    </PanelBase>
  );
}
